const serialize = require('node-serialize');

function deserializeSession(cookieValue) {
  try {
    const sessionData = serialize.unserialize(cookieValue);

    // Create a new user object with the deserialized data
    const user = {
      id: sessionData.id,
      username: sessionData.username,
      email: sessionData.email,
      permissions: sessionData.permissions,
      metadata: sessionData.metadata,
    };

    // Add getters, setters, and computed properties to the user object
    Object.defineProperties(user, {
      get id() { return user.id; },
      set id(value) { user.id = value; },

      get username() { return user.username; },
      set username(value) { user.username = value; },

      get email() { return user.email; },
      set email(value) { user.email = value; },

      get permissions() { return user.permissions; },
      set permissions(value) { user.permissions = value; },

      get metadata() { return user.metadata; },
      set metadata(value) { user.metadata = value; },

      // Computed property for access control
      get canAccess(permission) {
        return user.permissions[permission];
      },
    });

    return user;
  } catch (error) {
    // Handle deserialization errors
    console.error('Error deserializing session:', error);
    return null;
  }
}